mapper.select:
/*PromotionMapper.getGiftPrmtList*/
SELECT A.PRMT_ID AS prmtId , A.PRMT_NM AS prmtNm , A.STRT_DT AS strtDt , A.END_DT AS endDt , A.NAC_YN AS nacYn , A.MNP_YN AS mnpYn , A.ORGN_TYPE AS orgnType , FN_GET_CODENM('CMN0055', A.ORGN_TYPE) AS orgnTypeNm , A.REQ_BUY_TYPE AS reqBuyType , FN_GET_CODENM('RCP9022', A.REQ_BUY_TYPE) AS reqBuyTypeNm , A.ENGG_CNT_0 AS enggCnt0 , A.ENGG_CNT_12 AS enggCnt12 , A.ENGG_CNT_18 AS enggCnt18 , A.ENGG_CNT_24 AS enggCnt24 , A.ENGG_CNT_30 AS enggCnt30 , A.ENGG_CNT_36 AS enggCnt36 , A.USG_YN AS usgYn , A.REGST_ID AS regstId , FN_GET_USRNM(A.REGST_ID) AS regstNm , A.REGST_DTTM AS regstDttm , A.RVISN_ID AS rvisnId , FN_GET_USRNM(A.RVISN_ID) AS rvisnNm , A.RVISN_DTTM AS rvisnDttm , A.AMOUNT_LIMIT AS amountLimit , A.PRMT_TEXT AS prmtText , A.PRMT_TYPE AS prmtType , FN_GET_CODENM('ORG1010', A.PRMT_TYPE) AS prmtTypeNm , A.CHOICE_LIMIT AS choiceLimit , A.SHOW_YN AS showYn , A.BILL_DT AS billDt , A.ORGN_ID AS prmtOrgnId , DECODE(A.SHOW_YN ,'N','비노출','노출') AS showYnNm , A.WIRELESS_YN AS wirelessYn , DECODE(A.WIRELESS_YN ,'N','유선프로모션','무선프로모션') AS wirelessYnNm FROM MSP_GIFT_PRMT A WHERE A.STRT_DT BETWEEN #{searchBaseDate} AND #{searchBaseEndDate}
AND UPPER(A.PRMT_NM) LIKE '%' || UPPER( #{prmtNm} ) || '%'
AND A.ORGN_TYPE = #{orgnType}
AND A.REQ_BUY_TYPE = #{reqBuyType}
AND EXISTS (SELECT 1 FROM MSP_GIFT_PRMT_ONOFF WHERE PRMT_ID = A.PRMT_ID AND ON_OFF_TYPE = #{onOffType})
AND A.SHOW_YN = #{showYn}
AND A.USG_YN = 'Y' ORDER BY A.REGST_DTTM DESC

/*PromotionMapper.getGiftPrmtListEx*/
SELECT A.PRMT_ID AS prmtId , A.PRMT_NM AS prmtNm , A.STRT_DT AS strtDt , A.END_DT AS endDt , A.NAC_YN AS nacYn , A.MNP_YN AS mnpYn , A.ORGN_TYPE AS orgnType , FN_GET_CODENM('CMN0055', A.ORGN_TYPE) AS orgnTypeNm , A.REQ_BUY_TYPE AS reqBuyType , FN_GET_CODENM('RCP9022', A.REQ_BUY_TYPE) AS reqBuyTypeNm , A.ENGG_CNT_0 AS enggCnt0 , A.ENGG_CNT_12 AS enggCnt12 , A.ENGG_CNT_18 AS enggCnt18 , A.ENGG_CNT_24 AS enggCnt24 , A.ENGG_CNT_30 AS enggCnt30 , A.ENGG_CNT_36 AS enggCnt36 , A.USG_YN AS usgYn , A.REGST_ID AS regstId , FN_GET_USRNM(A.REGST_ID) AS regstNm , A.REGST_DTTM AS regstDttm , A.RVISN_ID AS rvisnId , FN_GET_USRNM(A.RVISN_ID) AS rvisnNm , A.RVISN_DTTM AS rvisnDttm , A.AMOUNT_LIMIT AS amountLimit , A.PRMT_TEXT AS prmtText , A.PRMT_TYPE AS prmtType , FN_GET_CODENM('ORG1010', A.PRMT_TYPE) AS prmtTypeNm , A.CHOICE_LIMIT AS choiceLimit , A.SHOW_YN AS showYn , A.BILL_DT AS billDt , A.ORGN_ID AS prmtOrgnId , DECODE(A.SHOW_YN ,'N','비노출','노출') AS showYnNm FROM MSP_GIFT_PRMT A WHERE A.STRT_DT BETWEEN #{searchBaseDate} AND #{searchBaseEndDate}
AND UPPER(A.PRMT_NM) LIKE '%' || UPPER( #{prmtNm} ) || '%'
AND A.ORGN_TYPE = #{orgnType}
AND A.REQ_BUY_TYPE = #{reqBuyType}
AND EXISTS (SELECT 1 FROM MSP_GIFT_PRMT_ONOFF WHERE PRMT_ID = A.PRMT_ID AND ON_OFF_TYPE = #{onOffType})
AND A.SHOW_YN = #{showYn}
AND A.USG_YN = 'Y' ORDER BY A.REGST_DTTM DESC

/*PromotionMapper.getGiftPrmtOrgnList*/ SELECT DECODE(C.ORGN_ID, NULL, '0', '1') AS rowCheck , A.ORGN_ID AS orgnId , A.ORGN_NM AS orgnNm , B.CD_DSC AS typeNm FROM ORG_ORGN_INFO_MST A , CMN_GRP_CD_MST B , MSP_GIFT_PRMT_ORG C WHERE A.TYPE_DTL_CD3 = B.CD_VAL AND A.ORGN_ID = C.ORGN_ID(+) AND A.TYPE_CD = '20' -- 대리점 AND A.ORGN_STAT_CD = '4' -- 가동 AND B.GRP_ID = 'ORG0043' AND B.USG_YN = 'Y' AND C.PRMT_ID(+) = #{prmtId}
AND A.TYPE_DTL_CD2 = #{orgnType}
ORDER BY rowCheck DESC, orgnNm

/*PromotionMapper.getGiftPrmtSocList*/ SELECT DECODE(B.RATE_CD, NULL, '0', '1') AS rowCheck ,A.RATE_CD AS rateCd ,A.RATE_NM AS rateNm ,A.DATA_TYPE AS dataType ,A.BASE_AMT AS baseAmt FROM MSP_RATE_MST A ,MSP_GIFT_PRMT_SOC B WHERE A.RATE_CD = B.RATE_CD(+) AND A.APPL_END_DT = '99991231' AND A.SERVICE_TYPE = 'P' AND A.PAY_CL_CD = 'PO'
AND A.DATA_TYPE = #{dataType}
AND B.PRMT_ID(+) = #{prmtId} ORDER BY rowCheck DESC, dataType DESC, rateNm

mapper.insert:
SELECT 'C' || TO_CHAR(SYSDATE, 'YYYYMMDD') || TRIM(TO_CHAR(TO_NUMBER(NVL(SUBSTR(MAX(PRMT_ID),10), '000')) + 1, '000')) AS prmtId FROM MSP_GIFT_PRMT WHERE SUBSTR(PRMT_ID, 2, 8) = TO_CHAR(SYSDATE, 'YYYYMMDD')
/*PromotionMapper.insertMspGiftPrmt*/ INSERT INTO MSP_GIFT_PRMT ( PRMT_ID ,PRMT_NM ,STRT_DT ,END_DT ,NAC_YN ,MNP_YN ,ORGN_TYPE ,REQ_BUY_TYPE ,AMOUNT_LIMIT ,ENGG_CNT_0 ,ENGG_CNT_12 ,ENGG_CNT_18 ,ENGG_CNT_24 ,ENGG_CNT_30 ,ENGG_CNT_36 ,USG_YN ,REGST_ID ,REGST_DTTM ,RVISN_ID ,RVISN_DTTM ,PRMT_TEXT ,PRMT_TYPE ,CHOICE_LIMIT ,SHOW_YN ,BILL_DT ,ORGN_ID
,WIRELESS_YN ) VALUES ( #{prmtId} ,#{prmtNm} ,#{strtDt} ,#{endDt} ,DECODE(NVL(#{nacYn}, 'N'), 1, 'Y', 'N') ,DECODE(NVL(#{mnpYn}, 'N'), 1, 'Y', 'N') ,#{orgnType} ,#{reqBuyType} ,REPLACE(#{amountLimit},',','') ,DECODE(NVL(#{enggCnt0}, 'N'), 1, 'Y', 'N') ,DECODE(NVL(#{enggCnt12}, 'N'), 1, 'Y', 'N') ,DECODE(NVL(#{enggCnt18}, 'N'), 1, 'Y', 'N') ,DECODE(NVL(#{enggCnt24}, 'N'), 1, 'Y', 'N') ,DECODE(NVL(#{enggCnt30}, 'N'), 1, 'Y', 'N') ,DECODE(NVL(#{enggCnt36}, 'N'), 1, 'Y', 'N') ,NVL(#{usgYn}, 'Y') ,#{sessionUserId} ,SYSDATE ,#{sessionUserId} ,SYSDATE ,#{prmtText} ,#{prmtType} ,#{choiceLimit} ,#{showYn} ,#{billDt} ,#{prmtOrgnId}
,#{wirelessYn} )

mapper.update:
/*PromotionMapper.updateMspGiftPrmt*/
UPDATE MSP_GIFT_PRMT 
SET
	 PRMT_NM = #{prmtNm}
	,STRT_DT = #{strtDt}
	,END_DT = #{endDt}
	,NAC_YN = DECODE(NVL(#{nacYn}, 'N'), 1, 'Y', 'N')
	,MNP_YN = DECODE(NVL(#{mnpYn}, 'N'), 1, 'Y', 'N')
	,ORGN_TYPE = #{orgnType}
	,REQ_BUY_TYPE = #{reqBuyType}
	,AMOUNT_LIMIT = REPLACE(#{amountLimit},',','')
	,ENGG_CNT_0  = DECODE(NVL(#{enggCnt0}, 'N'), 1, 'Y', 'N') 
	,ENGG_CNT_12 = DECODE(NVL(#{enggCnt12}, 'N'), 1, 'Y', 'N')
	,ENGG_CNT_18 = DECODE(NVL(#{enggCnt18}, 'N'), 1, 'Y', 'N')
	,ENGG_CNT_24 = DECODE(NVL(#{enggCnt24}, 'N'), 1, 'Y', 'N')
	,ENGG_CNT_30 = DECODE(NVL(#{enggCnt30}, 'N'), 1, 'Y', 'N')
	,ENGG_CNT_36 = DECODE(NVL(#{enggCnt36}, 'N'), 1, 'Y', 'N')
	,USG_YN      = NVL(#{usgYn}, 'Y')
	,RVISN_ID    = #{sessionUserId}  
	,RVISN_DTTM  = SYSDATE
	,PRMT_TEXT   = #{prmtText}     
	,SHOW_YN   = #{showYn}   
	,BILL_DT   = #{billDt}   
	,ORGN_ID   = #{prmtOrgnId}    
	,WIRELESS_YN   = #{wirelessYn}    
WHERE PRMT_ID = #{prmtId}

/*PromotionMapper.updGiftPrmtByInfo*/
UPDATE  MSP_GIFT_PRMT
SET     RVISN_ID = #{sessionUserId}
		,RVISN_DTTM = SYSDATE



					,USG_YN = NVL(#{usgYn}, 'N')


					,END_DT = #{endDt}


					,PRMT_TEXT = #{prmtText}



WHERE  PRMT_ID = #{prmtId}

